import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"先由去过我命本相","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/4.A级/先由去过我命本相.md","filePath":"4.资源分区/7.物品与装备/4.奇物/4.A级/先由去过我命本相.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/4.A级/先由去过我命本相.md"};function _(l,a,b,i,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"先由去过我命本相",tabindex:"-1"},[s("先由去过我命本相 "),e("a",{class:"header-anchor",href:"#先由去过我命本相","aria-label":'Permalink to "先由去过我命本相"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),o('<h1 id="先由去过我命本相-1" tabindex="-1">先由去过我命本相 <a class="header-anchor" href="#先由去过我命本相-1" aria-label="Permalink to &quot;先由去过我命本相&quot;">​</a></h1><p>先由去过我命本相<br> A+4000<br> 魔幻本质<br> 奇物(占据面部)<br> 描述：这是一副青铜祭礼面具，风格类似于三星堆青铜面具。上提眼角的纵目造型，耳部向外延伸，沉重古朴，但真正戴上之后，却仿若无足轻重。感知清晰，毫无遮掩，这副面具会自动调整脸型与纹路样式，将自身与佩戴者完全贴合，仿佛浑然天成。<br> 特性：【先由去过】【我命本相】<br> 【先由去过】：该物品具有影响部分时空的力量，当你看到一件物品时，可以立即看到这件物品过去最关键的经历与因果，通过曾经历的过去因果直接知晓物品的真名与实际效用。<br> 当你因任何原因死亡以后，你的肉体不仅不会被摧毁，反而会凝固修复至完好模样。在你死后，这副面具会将你死亡这一事实的因果顺序倒转，无视死亡的经过，只取死因与现在的结果。<br> 因为你的现在已是死的，所以过去的你才会经历死亡。<br> 而你的尸体将保持该种状态继续向未来保存，直到达到死亡这一结果后才会开始腐烂与承受破坏，又因死亡是你的过去，故此，你的尸体将永不腐烂，永不损伤。<br> 与此同时，由于倒悬了死亡的因果，你的肉体可以在此期间缓慢复苏，基础的复苏时间为1个月。根据你死前在战斗场景中承受的伤害计算，每承受24L都需要额外一个月时间来修复，不足24L按一个月计算。若死于即死，则额外需要两个月时间。复苏的时间结束之后，你将会重新在自己这具身躯上再现生机，于未来重新复活，这是一个B级命运来源的复活能力。<br> 由于死亡的时机是在过去，如此复活不会因为改变因果或化死为生而遭受世界的惩罚。<br> 虽然遗体无法破坏，但是复活是有迹可寻的。在你死后，你只能以灵体的方式在世间存续，无法进行任何除了移动以外的行为，你的死躯会拥有等同于你自身最大生命值的特殊构造值，分布于用于复活而建立在全身的103处关窍当中，敌人对你的尸体造成的伤害会导致关窍与线路断裂，从而破坏复活进度，若你全身的窍穴被完全破坏(即尸体构造值因攻击而清空)，则复活失败，将会化作彻底的尸体而无法获得重生，仅能保留遗体不被破坏的特性。<br> 无论是否重生成功，该重生能力在每个影片内仅会生效一次。</p><p>【我命本相】：通过该护符坚定自我性命，你在强韧豁免上获取到【8加骰】的益处，并且免疫A级创伤来源的负面效果。佩戴上这副面具之后，你可以获得真正的本我之相，这意味着你可以随时改换自身除了这副面具之外的体型、性别、穿着乃至气息等等，并且天衣无缝，浑然天成，仿佛本就注定以此形态存续于世般自然，故此不限制伪装时间，这是一个B级附身来源的伪装效果。在战斗场景中，每个战斗中的行动轮结束时，若你是这一轮中造成伤害最多的单位，则威仪立即开始生效，你选择一项你拥有的免疫，接下来的一轮中那项免疫提高一级，这是一个来源于这副面具本身提供的本相带来的【威仪】特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
